const int base = 131;
void solve(int CASE)
{
	ll n, m; cin >> n >> m;
	var a = vector<string>(n + 1);
	fa(i, 1, n)cin >> a[i], a[i] = ' ' + a[i];
	var mp = gpHashMap<ull, ll>();
	fa(i, 1, m) {
		string s; cin >> s;
		ll x; cin >> x;
		ull hs = 0;
		fa(i, 0, vs(s))hs = hs * base + s[i] - 'a' + 1; // 字符串哈希
		mp[hs] = x;
	}

	ll ans = 0;

	fa(i, 1, n) {
		ull hs = 0;
		int len = 0;
		fa(j, 1, n) {
			if (a[i][j] == '#') {
				if (len) {
					if (mp.find(hs) == mp.end()) {
						cout << "-1" << endl;
						return;
					}
					ans += mp[hs];
				}
				hs = len = 0;
			}
			else {
				hs = hs * base + a[i][j] - 'a' + 1;
				len++;
			}
		}
		if (len) {
			if (mp.find(hs) == mp.end()) {
				cout << "-1" << endl;
				return;
			}
			ans += mp[hs];
		}
	}
	fa(j, 1, n) {
		ull hs = 0;
		int len = 0;
		fa(i, 1, n) {
			if (a[i][j] == '#') {
				if (len) {
					if (mp.find(hs) == mp.end()) {
						cout << "-1" << endl;
						return;
					}
					ans += mp[hs];
				}
				hs = len = 0;
			}
			else {
				hs = hs * base + a[i][j] - 'a' + 1;
				len++;
			}
		}
		if (len) {
			if (mp.find(hs) == mp.end()) {
				cout << "-1" << endl;
				return;
			}
			ans += mp[hs];
		}
	}

	cout << ans << endl;
	return;
}
